// =====================================================
// 1. Evento bruto vindo do Rabbit
// =====================================================
const rabbitEvent = Array.isArray($json) ? $json[0] : $json;

// Se vier encapsulado em "content" (string JSON)
const event = rabbitEvent.content
  ? JSON.parse(rabbitEvent.content)
  : rabbitEvent;

// =====================================================
// 2. Extrai o NÚMERO DA INSTÂNCIA (FONTE ÚNICA)
// =====================================================
// Exemplo: "554299093429:19@s.whatsapp.net"
const userJID = event.userJID || null;

const numeroInstancia = userJID
  ? userJID.split(":")[0].replace(/\D/g, "")
  : null;

// =====================================================
// 3. Mapa MANUAL de instâncias
// =====================================================
const mapaPorNumero = {
  "553497340123": {
    identificador: "Numero_1",
    inbox_id: 7,
    dinastia_instance: "instance_1",
    dinastia_token: "abcbaac1-aef7-4ea3-ae34-9af61dca26bb"
  },

  "553498268523": {
    identificador: "Numero_2",
    inbox_id: 10,
    dinastia_instance: "instance_2",
    dinastia_token: "fb29784a-0b59-41fd-8b24-9ff551999e07"
  },

  "554588422548": {
    identificador: "Instancia David-Jesreel",
    inbox_id: 0,
    dinastia_instance: "instance_3",
    dinastia_token: "llDoaLv2P9lYOyuIgwPoWboyavOGfALs"
  }
};

// =====================================================
// 4. Funções auxiliares
// =====================================================
function lastDigits(numero, tamanho) {
  return numero.slice(-tamanho);
}

// =====================================================
// 5. Resolução da config
// =====================================================
let config = null;
let estrategia = null;

// 5.1 Match exato
if (numeroInstancia && mapaPorNumero[numeroInstancia]) {
  config = mapaPorNumero[numeroInstancia];
  estrategia = "match_exato";
}

// 5.2 Match maleável (últimos 8 ou 9 dígitos)
if (!config && numeroInstancia) {
  const inst8 = lastDigits(numeroInstancia, 8);
  const inst9 = lastDigits(numeroInstancia, 9);

  for (const [numeroMapeado, cfg] of Object.entries(mapaPorNumero)) {
    if (
      lastDigits(numeroMapeado, 8) === inst8 ||
      lastDigits(numeroMapeado, 9) === inst9
    ) {
      config = cfg;
      estrategia = "match_maleavel";
      break;
    }
  }
}

// 5.3 Fallback (primeira instância cadastrada)
if (!config) {
  config = Object.values(mapaPorNumero)[0];
  estrategia = "fallback";
}

// =====================================================
// 6. Retorno final
// =====================================================
return {
  ...event,
  _meta: {
    userJID_original: userJID,
    numero_instancia_resolvido: numeroInstancia,
    estrategia_match: estrategia
  },
  _config: config
};

