// ==========================================
// CONFIGURAÇÃO (edite aqui facilmente)
// ==========================================
const CONFIG = {
  api_url: 'https://aplic_tech-dinastiapi.trcjj4.easypanel.host',
  tokens: [
    'abcbaac1-aef7-4ea3-ae34-9af61dca26bb',
    'fb29784a-0b59-41fd-8b24-9ff551999e07',
    'b9e1ca87387d023ef42678b1a1cdd2a6b6aac173ed576ef56375bca7712a36bb'
  ],
  timeout: 8000,
  debug: false
};


// ==========================================
// SANITIZAÇÃO: converte strings "null"/"undefined" para null real
// ==========================================
function sanitizarNulos(obj) {
  if (obj === null || obj === undefined) return null;
  if (typeof obj === 'string') {
    if (obj === 'null' || obj === 'undefined' || obj.trim() === '') return null;
    return obj;
  }
  if (Array.isArray(obj)) return obj.map(sanitizarNulos);
  if (typeof obj === 'object') {
    const resultado = {};
    for (const [chave, valor] of Object.entries(obj)) {
      resultado[chave] = sanitizarNulos(valor);
    }
    return resultado;
  }
  return obj;
}


// ==========================================
// HELPER: PUSH COM DEBUG CONDICIONAL
// ==========================================
function montarSaida(base, whatsapp, debug) {
  const saida = { ...base, _whatsapp: sanitizarNulos(whatsapp) };
  if (CONFIG.debug) {
    saida._debug = debug.getLogs();
    saida._debug_resumo = debug.getResumo();
  }
  return { json: saida };
}


// ==========================================
// SISTEMA DE DEBUG
// ==========================================
class DebugLogger {
  constructor() {
    this.logs = [];
    this.startTime = Date.now();
  }

  log(etapa, dados, nivel = 'info') {
    const timestamp = Date.now() - this.startTime;
    const logEntry = { timestamp: `+${timestamp}ms`, etapa, nivel, dados };
    this.logs.push(logEntry);
    if (CONFIG.debug) console.log(`[${timestamp}ms] ${etapa}:`, dados);
  }

  erro(etapa, erro) {
    this.log(etapa, { erro: erro.message || erro }, 'erro');
  }

  sucesso(etapa, dados) {
    this.log(etapa, dados, 'sucesso');
  }

  getLogs() { return this.logs; }

  getResumo() {
    return {
      total_etapas: this.logs.length,
      tempo_total: `${Date.now() - this.startTime}ms`,
      erros: this.logs.filter(l => l.nivel === 'erro').length,
      sucessos: this.logs.filter(l => l.nivel === 'sucesso').length
    };
  }
}


// ==========================================
// EXTRAÇÃO INTELIGENTE DE IDENTIFICADORES
// FIX: lógica por sufixo, sem assumir qual campo carrega qual tipo
// FIX: @lid duplicado corrigido com split('@')[0] antes de reconstruir
// ==========================================
function extrairIdentificadores(info, debug) {
  const isFromMe = info.IsFromMe === true;

  // IsFromMe = true  → lead é o DESTINATÁRIO → Chat (primário) + RecipientAlt (secundário)
  // IsFromMe = false → lead é o REMETENTE    → Sender (primário) + SenderAlt (secundário) + Chat (fallback)
  const camposLead = isFromMe
    ? [info.Chat, info.RecipientAlt]
    : [info.Sender, info.SenderAlt, info.Chat];

  debug.log('INICIO_EXTRACAO_IDENTIFICADORES', {
    is_from_me: isFromMe,
    campos_lead: camposLead
  });

  let jid = null;
  let lid = null;

  for (const campo of camposLead) {
    if (!campo || typeof campo !== 'string' || campo.trim() === '') continue;

    if (!jid && campo.includes('@s.whatsapp.net')) {
      // Remove device suffix (:X) antes de reconstruir
      jid = campo.split('@')[0].split(':')[0] + '@s.whatsapp.net';
      debug.log('JID_ENCONTRADO', { campo, jid });
    }

    if (!lid && campo.includes('@lid')) {
      // FIX: split('@')[0] garante que não duplica @lid se já vier com sufixo
      lid = campo.split('@')[0].split(':')[0] + '@lid';
      debug.log('LID_ENCONTRADO', { campo, lid });
    }
  }

  const identificador = jid || lid;

  debug.log('IDENTIFICADORES_SELECIONADOS', { jid, lid, identificador_ativo: identificador });

  return { jid, lid, identificador };
}


// ==========================================
// EXTRAÇÃO INTELIGENTE DE MENSAGEM
// ==========================================
function extrairMensagem(message, debug) {
  if (!message) {
    debug.log('MENSAGEM_AUSENTE', 'Objeto Message não existe');
    return { texto: "", tipo: "vazio", midia: null };
  }

  let texto = "";
  let tipo = "texto";
  let midia = null;

  if (message.conversation) {
    texto = message.conversation;
    tipo = "conversation";
  } else if (message.extendedTextMessage?.text) {
    texto = message.extendedTextMessage.text;
    tipo = "extendedText";
  } else if (message.imageMessage) {
    texto = message.imageMessage.caption || "";
    tipo = "image";
    midia = {
      tipo: "image",
      mimetype: message.imageMessage.mimetype || null,
      caption: message.imageMessage.caption || null,
      url: message.imageMessage.URL || null,
      tamanho: message.imageMessage.fileLength || null
    };
  } else if (message.videoMessage) {
    texto = message.videoMessage.caption || "";
    tipo = "video";
    midia = {
      tipo: "video",
      mimetype: message.videoMessage.mimetype || null,
      caption: message.videoMessage.caption || null,
      url: message.videoMessage.URL || null,
      tamanho: message.videoMessage.fileLength || null
    };
  } else if (message.documentMessage) {
    texto = message.documentMessage.caption || message.documentMessage.fileName || "";
    tipo = "document";
    midia = {
      tipo: "document",
      mimetype: message.documentMessage.mimetype || null,
      filename: message.documentMessage.fileName || null,
      caption: message.documentMessage.caption || null,
      tamanho: message.documentMessage.fileLength || null
    };
  } else if (message.audioMessage) {
    texto = "[Áudio]";
    tipo = "audio";
    midia = {
      tipo: "audio",
      mimetype: message.audioMessage.mimetype || null,
      duracao: message.audioMessage.seconds || null,
      tamanho: message.audioMessage.fileLength || null
    };
  }

  debug.log('MENSAGEM_EXTRAIDA', {
    tipo,
    texto_preview: texto ? texto.substring(0, 50) : '(vazio)',
    tamanho: texto.length,
    tem_midia: !!midia
  });

  return { texto, tipo, midia };
}


// ==========================================
// EXTRAÇÃO DE DADOS DO WEBHOOK
// ==========================================
function extrairDadosWebhook(item, debug) {
  debug.log('INICIO_EXTRACAO', {
    estrutura_recebida: Object.keys(item.json)
  });

  const json = item.json;
  const info = json.data?.event?.Info;
  const message = json.data?.event?.Message;

  if (!info) {
    debug.erro('ESTRUTURA_INVALIDA', 'Não encontrou data.event.Info');
    return {
      identificador: null,
      jid: null,
      lid: null,
      nome: null,
      mensagem: "",
      tipo_mensagem: "vazio",
      midia: null,
      is_from_me: null,
      webhook_completo: json
    };
  }

  const isFromMe = info.IsFromMe === true;

  const ids = extrairIdentificadores(info, debug);
  const msg = extrairMensagem(message, debug);

  const nome = isFromMe ? null : (info.PushName || null);

  debug.log('NOME_EXTRAIDO', {
    is_from_me: isFromMe,
    push_name_raw: info.PushName,
    nome_final: nome
  });

  return {
    identificador: ids.identificador,
    jid: ids.jid,
    lid: ids.lid,
    nome,
    mensagem: msg.texto,
    tipo_mensagem: msg.tipo,
    midia: msg.midia,
    is_from_me: isFromMe,
    webhook_completo: json
  };
}


// ==========================================
// IDENTIFICAÇÃO DE TIPO
// ==========================================
function identificarTipo(input, debug) {
  debug.log('INICIO_IDENTIFICACAO_TIPO', { input });

  if (!input) {
    debug.erro('IDENTIFICACAO_TIPO', 'Input vazio ou null');
    return { tipo: 'invalido', valor: null, telefone: null };
  }

  if (input.includes('@s.whatsapp.net')) {
    const telefone = input.split('@')[0].split(':')[0];
    debug.sucesso('TIPO_IDENTIFICADO', { tipo: 'JID', telefone, input_completo: input });
    return { tipo: 'jid', valor: input, telefone };
  }

  if (input.includes('@lid')) {
    debug.sucesso('TIPO_IDENTIFICADO', { tipo: 'LID', input_completo: input });
    return { tipo: 'lid', valor: input, telefone: null };
  }

  debug.erro('TIPO_IDENTIFICADO', { tipo: 'DESCONHECIDO', input });
  return { tipo: 'desconhecido', valor: input, telefone: null };
}


// ==========================================
// REQUISIÇÃO POST COM FALLBACK (body JSON)
// ==========================================
async function requisicaoPostComFallback(endpoint, body, debug) {
  debug.log('INICIO_REQUISICAO_POST', { endpoint, body, total_tokens: CONFIG.tokens.length });

  let ultimoErro = null;
  let tentativa = 0;

  for (const token of CONFIG.tokens) {
    tentativa++;
    const tokenMascara = token.substring(0, 8) + '...';

    debug.log(`TENTATIVA_POST_${tentativa}`, { token: tokenMascara, url: `${CONFIG.api_url}${endpoint}` });

    try {
      const inicio = Date.now();

      const response = await this.helpers.httpRequest({
        method: 'POST',
        url: `${CONFIG.api_url}${endpoint}`,
        headers: {
          'Content-Type': 'application/json',
          'token': token
        },
        body: JSON.stringify(body),
        timeout: CONFIG.timeout,
      });

      const tempoResposta = Date.now() - inicio;
      debug.log(`RESPOSTA_POST_TENTATIVA_${tentativa}`, { tempo: `${tempoResposta}ms` });

      const data = typeof response === 'string' ? JSON.parse(response) : response;

      if (Array.isArray(data) && data.length > 0) {
        const primeiro = data[0];
        if (primeiro.success && primeiro.data) {
          debug.sucesso('REQUISICAO_POST_SUCESSO', { tentativa, token: tokenMascara });
          return { sucesso: true, dados: primeiro.data, token_usado: tokenMascara };
        }
      }
      debug.log(`TENTATIVA_POST_${tentativa}_FALHOU`, { motivo: 'Resposta sem estrutura esperada' });
      continue;

    } catch (erro) {
      ultimoErro = erro.message;
      debug.erro(`TENTATIVA_POST_${tentativa}_EXCEPTION`, { erro: erro.message });
      continue;
    }
  }

  debug.erro('TODAS_TENTATIVAS_POST_FALHARAM', { total_tentativas: tentativa, ultimo_erro: ultimoErro });
  return { sucesso: false, erro: 'all_tokens_failed', mensagem: ultimoErro || 'Todos tokens falharam' };
}


// ==========================================
// REQUISIÇÃO GET COM FALLBACK (query string)
// FIX: endpoint /user/lid/from-lid espera GET + query string, não POST + body
// ==========================================
async function requisicaoGetComFallback(endpoint, params, debug) {
  debug.log('INICIO_REQUISICAO_GET', { endpoint, params, total_tokens: CONFIG.tokens.length });

  let ultimoErro = null;
  let tentativa = 0;

  for (const token of CONFIG.tokens) {
    tentativa++;
    const tokenMascara = token.substring(0, 8) + '...';

    debug.log(`TENTATIVA_GET_${tentativa}`, { token: tokenMascara, url: `${CONFIG.api_url}${endpoint}` });

    try {
      const inicio = Date.now();

      // Monta query string manualmente (URLSearchParams não disponível no n8n)
      const qs = Object.entries(params).map(([k, v]) => `${k}=${encodeURIComponent(v)}`).join('&');
      const urlComParams = `${CONFIG.api_url}${endpoint}?${qs}`;

      const response = await this.helpers.httpRequest({
        method: 'GET',
        url: urlComParams,
        headers: {
          'token': token
        },
        timeout: CONFIG.timeout,
      });

      const tempoResposta = Date.now() - inicio;
      debug.log(`RESPOSTA_GET_TENTATIVA_${tentativa}`, { tempo: `${tempoResposta}ms` });

      const data = typeof response === 'string' ? JSON.parse(response) : response;

      if (Array.isArray(data) && data.length > 0) {
        const primeiro = data[0];
        if (primeiro.success && primeiro.data) {
          debug.sucesso('REQUISICAO_GET_SUCESSO', { tentativa, token: tokenMascara });
          return { sucesso: true, dados: primeiro.data, token_usado: tokenMascara };
        }
      }
      // Tenta estrutura direta (objeto único)
      if (data && data.success && data.data) {
        debug.sucesso('REQUISICAO_GET_SUCESSO_DIRETO', { tentativa, token: tokenMascara });
        return { sucesso: true, dados: data.data, token_usado: tokenMascara };
      }
      debug.log(`TENTATIVA_GET_${tentativa}_FALHOU`, { motivo: 'Resposta sem estrutura esperada', body: data });
      continue;

    } catch (erro) {
      ultimoErro = erro.message;
      debug.erro(`TENTATIVA_GET_${tentativa}_EXCEPTION`, { erro: erro.message });
      continue;
    }
  }

  debug.erro('TODAS_TENTATIVAS_GET_FALHARAM', { total_tentativas: tentativa, ultimo_erro: ultimoErro });
  return { sucesso: false, erro: 'all_tokens_failed', mensagem: ultimoErro || 'Todos tokens falharam' };
}


// ==========================================
// RESOLUÇÃO LID → JID
// Tenta GET primeiro, fallback para POST se falhar
// ==========================================
async function resolverLidParaJid(lid, debug) {
  debug.log('RESOLVER_LID_PARA_JID', { lid });

  const resultadoGet = await requisicaoGetComFallback('/user/lid/from-lid', { lid }, debug);
  if (resultadoGet.sucesso) return resultadoGet;

  debug.log('RESOLVER_LID_PARA_JID_FALLBACK_POST', { motivo: resultadoGet.erro });
  return await requisicaoPostComFallback('/user/lid/from-lid', { lid }, debug);
}


// ==========================================
// RESOLUÇÃO JID → LID
// Tenta GET primeiro, fallback para POST se falhar
// ==========================================
async function resolverJidParaLid(jid, debug) {
  const numeroLimpo = jid.split('@')[0].split(':')[0];

  debug.log('RESOLVER_JID_PARA_LID', { jid_original: jid, phone_enviado: numeroLimpo });

  const resultadoGet = await requisicaoGetComFallback('/user/lid/get', { phone: numeroLimpo }, debug);

  if (resultadoGet.sucesso) {
    if (resultadoGet.dados.has_lid && resultadoGet.dados.lid) {
      debug.sucesso('LID_ENCONTRADO_PARA_JID', { lid: resultadoGet.dados.lid });
      return resultadoGet;
    } else {
      debug.log('JID_SEM_LID', 'Número válido mas sem LID');
      return { sucesso: false, erro: 'no_lid', mensagem: 'Número válido mas sem LID' };
    }
  }

  debug.log('RESOLVER_JID_PARA_LID_FALLBACK_POST', { motivo: resultadoGet.erro });
  const resultadoPost = await requisicaoPostComFallback('/user/lid/get', { phone: numeroLimpo }, debug);

  if (resultadoPost.sucesso) {
    if (resultadoPost.dados.has_lid && resultadoPost.dados.lid) {
      debug.sucesso('LID_ENCONTRADO_PARA_JID_VIA_POST', { lid: resultadoPost.dados.lid });
      return resultadoPost;
    } else {
      debug.log('JID_SEM_LID_VIA_POST', 'Número válido mas sem LID');
      return { sucesso: false, erro: 'no_lid', mensagem: 'Número válido mas sem LID' };
    }
  }

  return resultadoPost;
}


// ==========================================
// PROCESSAMENTO PRINCIPAL
// ==========================================
const items = $('Extrair Conteudo').all();
const resultados = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const debug = new DebugLogger();

  debug.log('PROCESSANDO_ITEM', { index: i + 1, total: items.length });

  const webhook = extrairDadosWebhook(item, debug);

  if (!webhook.identificador) {
    debug.erro('VALIDACAO_WEBHOOK', 'Identificador não encontrado');

    resultados.push(montarSaida(item.json, {
      erro: 'identificador_ausente',
      mensagem: 'Não foi possível extrair JID/LID do webhook',
      is_from_me: webhook.is_from_me
    }, debug));
    continue;
  }

  // CASO: JÁ TEM LID E JID (comum em IsFromMe=true com ambos os campos presentes)
  if (webhook.lid && webhook.jid) {
    debug.log('JID_E_LID_DISPONIVEIS', {
      lid: webhook.lid,
      jid: webhook.jid,
      is_from_me: webhook.is_from_me
    });

    const telefone = webhook.jid.split('@')[0].split(':')[0];

    const dadosFinais = {
      identificador_recebido: webhook.identificador,
      tipo_recebido: 'jid_com_lid',
      nome_contato: webhook.nome,
      mensagem_recebida: webhook.mensagem,
      tipo_mensagem: webhook.tipo_mensagem,
      midia: webhook.midia,
      jid: webhook.jid,
      lid: webhook.lid,
      telefone,
      identificador_ativo: webhook.jid,
      resolvido: true,
      has_lid: true,
      is_from_me: webhook.is_from_me,
      erro: null
    };

    debug.sucesso('JID_E_LID_JA_RESOLVIDOS', dadosFinais);
    resultados.push(montarSaida(webhook.webhook_completo, dadosFinais, debug));
    continue;
  }

  // FLUXO NORMAL: só tem um dos dois
  const identificacao = identificarTipo(webhook.identificador, debug);

  let dadosFinais = {
    identificador_recebido: webhook.identificador,
    tipo_recebido: identificacao.tipo,
    nome_contato: webhook.nome,
    mensagem_recebida: webhook.mensagem,
    tipo_mensagem: webhook.tipo_mensagem,
    midia: webhook.midia,
    jid: webhook.jid,
    lid: webhook.lid,
    telefone: null,
    identificador_ativo: webhook.identificador,
    resolvido: false,
    has_lid: !!webhook.lid,
    is_from_me: webhook.is_from_me,
    erro: null
  };

  if (identificacao.tipo === 'jid') {
    dadosFinais.telefone = identificacao.telefone;
    dadosFinais.identificador_ativo = identificacao.valor;
    dadosFinais.resolvido = true;

    debug.sucesso('JID_PROCESSADO', { jid: dadosFinais.jid, telefone: dadosFinais.telefone });

    // Tenta enriquecer com LID se não tiver
    if (!dadosFinais.lid) {
      const resultadoLid = await resolverJidParaLid(identificacao.valor, debug);
      if (resultadoLid.sucesso) {
        dadosFinais.lid = resultadoLid.dados.lid;
        dadosFinais.has_lid = true;
      }
    }

  } else if (identificacao.tipo === 'lid') {
    // FIX: agora usa GET com query string corretamente
    const resultado = await resolverLidParaJid(identificacao.valor, debug);

    if (resultado.sucesso) {
      dadosFinais.jid = resultado.dados.phone;

      const partes = resultado.dados.phone.split('@')[0];
      dadosFinais.telefone = partes.split(':')[0];

      dadosFinais.identificador_ativo = resultado.dados.phone;
      dadosFinais.resolvido = true;

      debug.sucesso('LID_RESOLVIDO', {
        lid_original: dadosFinais.lid,
        jid_encontrado: dadosFinais.jid,
        telefone: dadosFinais.telefone
      });
    } else {
      dadosFinais.resolvido = false;
      dadosFinais.erro = resultado.erro;

      debug.erro('FALHA_RESOLVER_LID', { erro: resultado.erro });
    }
  }

  resultados.push(montarSaida(webhook.webhook_completo, dadosFinais, debug));
}

return resultados;

