parameters.jsCode:
// ==========================================
// CONFIGURAÇÃO (edite aqui facilmente)
// ==========================================
const CONFIG = {
  api_url: 'https://aplic_tech-dinastiapi.trcjj4.easypanel.host',
  tokens: [
    'abcbaac1-aef7-4ea3-ae34-9af61dca26bb',
    'fb29784a-0b59-41fd-8b24-9ff551999e07',    'b9e1ca87387d023ef42678b1a1cdd2a6b6aac173ed576ef56375bca7712a36bb'
  ],
  timeout: 5000, // 5 segundos
  debug: true // ATIVE/DESATIVE DEBUG AQUI
};


// ==========================================
// SISTEMA DE DEBUG
// ==========================================
class DebugLogger {
  constructor() {
    this.logs = [];
    this.startTime = Date.now();
  }

  log(etapa, dados, nivel = 'info') {
    const timestamp = Date.now() - this.startTime;
    const logEntry = {
      timestamp: `+${timestamp}ms`,
      etapa,
      nivel,
      dados
    };

    this.logs.push(logEntry);

    if (CONFIG.debug) {
      console.log(`[${timestamp}ms] ${etapa}:`, dados);
    }
  }

  erro(etapa, erro) {
    this.log(etapa, { erro: erro.message || erro }, 'erro');
  }

  sucesso(etapa, dados) {
    this.log(etapa, dados, 'sucesso');
  }

  getLogs() {
    return this.logs;
  }

  getResumo() {
    return {
      total_etapas: this.logs.length,
      tempo_total: `${Date.now() - this.startTime}ms`,
      erros: this.logs.filter(l => l.nivel === 'erro').length,
      sucessos: this.logs.filter(l => l.nivel === 'sucesso').length
    };
  }
}

// ==========================================
// EXTRAÇÃO INTELIGENTE DE IDENTIFICADORES
// ==========================================
function extrairIdentificadores(info, debug) {
  debug.log('INICIO_EXTRACAO_IDENTIFICADORES', {
    chat: info.Chat,
    sender: info.Sender,
    sender_alt: info.SenderAlt
  });

  // Coleta APENAS campos do remetente
  const camposRemetente = [
    info.Chat,
    info.Sender,
    info.SenderAlt
  ].filter(x => x && typeof x === 'string');

  // Separa JIDs e LIDs
  const jids = camposRemetente.filter(x => x.includes('@s.whatsapp.net'));
const lids = camposRemetente
  .filter(x => x.includes('@lid'))
  .map(x => {
    // Remove :XX se tiver E garante apenas um @lid
    const limpo = x.replace('@lid', '');  // remove @lid temporariamente
    const semDevice = limpo.split(':')[0]; // remove :XX
    return semDevice + '@lid';             // adiciona @lid de volta
  });


  debug.log('IDENTIFICADORES_COLETADOS', {
    total_campos: camposRemetente.length,
    jids_encontrados: jids.length,
    lids_encontrados: lids.length,
    jids,
    lids
  });

  // Prioriza JID "limpo" (sem :XX device ID)
  const jidLimpo = jids.find(x => !x.includes(':')) || jids[0] || null;
  const lidPrincipal = lids[0] || null;

  // Identificador ativo: prefere JID limpo
  const identificadorAtivo = jidLimpo || lidPrincipal;

  debug.log('IDENTIFICADORES_SELECIONADOS', {
    jid_principal: jidLimpo,
    lid_principal: lidPrincipal,
    identificador_ativo: identificadorAtivo
  });

  return {
    jid: jidLimpo,
    lid: lidPrincipal,
    identificador: identificadorAtivo
  };
}

// ==========================================
// EXTRAÇÃO INTELIGENTE DE MENSAGEM
// ==========================================
function extrairMensagem(message, debug) {
  if (!message) {
    debug.log('MENSAGEM_AUSENTE', 'Objeto Message não existe');
    return {
      texto: "",
      tipo: "vazio",
      midia: null
    };
  }

  let texto = "";
  let tipo = "texto";
  let midia = null;

  // Tenta todos os formatos possíveis
  if (message.conversation) {
    texto = message.conversation;
    tipo = "conversation";
  }
  else if (message.extendedTextMessage?.text) {
    texto = message.extendedTextMessage.text;
    tipo = "extendedText";
  }
  else if (message.imageMessage) {
    texto = message.imageMessage.caption || "";
    tipo = "image";
    midia = {
      tipo: "image",
      mimetype: message.imageMessage.mimetype,
      caption: message.imageMessage.caption || "",
      url: message.imageMessage.URL,
      tamanho: message.imageMessage.fileLength
    };
  }
  else if (message.videoMessage) {
    texto = message.videoMessage.caption || "";
    tipo = "video";
    midia = {
      tipo: "video",
      mimetype: message.videoMessage.mimetype,
      caption: message.videoMessage.caption || "",
      url: message.videoMessage.URL,
      tamanho: message.videoMessage.fileLength
    };
  }
  else if (message.documentMessage) {
    texto = message.documentMessage.caption || message.documentMessage.fileName || "";
    tipo = "document";
    midia = {
      tipo: "document",
      mimetype: message.documentMessage.mimetype,
      filename: message.documentMessage.fileName,
      caption: message.documentMessage.caption || "",
      tamanho: message.documentMessage.fileLength
    };
  }
  else if (message.audioMessage) {
    texto = "[Áudio]";
    tipo = "audio";
    midia = {
      tipo: "audio",
      mimetype: message.audioMessage.mimetype,
      duracao: message.audioMessage.seconds,
      tamanho: message.audioMessage.fileLength
    };
  }

  debug.log('MENSAGEM_EXTRAIDA', {
    tipo,
    texto_preview: texto ? texto.substring(0, 50) : '(vazio)',
    tamanho: texto.length,
    tem_midia: !!midia
  });

  return { texto, tipo, midia };
}

// ==========================================
// EXTRAÇÃO DE DADOS DO WEBHOOK
// ==========================================
function extrairDadosWebhook(item, debug) {
  debug.log('INICIO_EXTRACAO', { 
    estrutura_recebida: Object.keys(item.json)
  });

  const json = item.json;
  const info = json.data?.event?.Info;
  const message = json.data?.event?.Message;

  if (!info) {
    debug.erro('ESTRUTURA_INVALIDA', 'Não encontrou data.event.Info');
    return {
      identificador: null,
      jid: null,
      lid: null,
      nome: "Sem nome",
      mensagem: "",
      tipo_mensagem: "vazio",
      midia: null,
      webhook_completo: json
    };
  }

  // Extrai identificadores de forma inteligente
  const ids = extrairIdentificadores(info, debug);

  // Extrai mensagem de forma inteligente
  const msg = extrairMensagem(message, debug);

  // Nome
  const nome = info.PushName || json.pushName || "Sem nome";

  debug.log('NOME_EXTRAIDO', { valor: nome });

  return {
    identificador: ids.identificador,
    jid: ids.jid,
    lid: ids.lid,
    nome,
    mensagem: msg.texto,
    tipo_mensagem: msg.tipo,
    midia: msg.midia,
    webhook_completo: json
  };
}

// ==========================================
// IDENTIFICAÇÃO DE TIPO
// ==========================================
function identificarTipo(input, debug) {
  debug.log('INICIO_IDENTIFICACAO_TIPO', { input });

  if (!input) {
    debug.erro('IDENTIFICACAO_TIPO', 'Input vazio ou null');
    return { tipo: 'invalido', valor: null, telefone: null };
  }

  if (input.includes('@s.whatsapp.net')) {
    // Extrai telefone do JID (remove @s.whatsapp.net e device ID)
    const partes = input.split('@')[0];  // "5534999887766:58" ou "5534999887766"
    const telefone = partes.split(':')[0];  // "5534999887766"

    debug.sucesso('TIPO_IDENTIFICADO', {
      tipo: 'JID',
      telefone,
      input_completo: input
    });
    return {
      tipo: 'jid',
      valor: input,
      telefone  // ← EXATAMENTE como veio do WhatsApp
    };
  }

  if (input.includes('@lid')) {
    debug.sucesso('TIPO_IDENTIFICADO', {
      tipo: 'LID',
      input_completo: input
    });
    return {
      tipo: 'lid',
      valor: input,
      telefone: null
    };
  }

  debug.erro('TIPO_IDENTIFICADO', {
    tipo: 'DESCONHECIDO',
    input
  });
  return { tipo: 'desconhecido', valor: input, telefone: null };
}

// ==========================================
// REQUISIÇÃO COM FALLBACK
// ==========================================
async function requisicaoComFallback(endpoint, body, debug) {
  debug.log('INICIO_REQUISICAO', {
    endpoint,
    body,
    total_tokens: CONFIG.tokens.length
  });

  let ultimoErro = null;
  let tentativa = 0;

  for (const token of CONFIG.tokens) {
    tentativa++;
    const tokenMascara = token.substring(0, 8) + '...';

    debug.log(`TENTATIVA_${tentativa}`, {
      token: tokenMascara,
      url: `${CONFIG.api_url}${endpoint}`
    });

    try {
      const inicio = Date.now();

      const response = await $http.request({
        method: 'POST',
        url: `${CONFIG.api_url}${endpoint}`,
        headers: {
          'Content-Type': 'application/json',
          'token': token
        },
        body: body,
        json: true,
        timeout: CONFIG.timeout,
        returnFullResponse: true
      });

      const tempoResposta = Date.now() - inicio;

      debug.log(`RESPOSTA_TENTATIVA_${tentativa}`, {
        status: response.statusCode,
        tempo: `${tempoResposta}ms`
      });

      if (response.statusCode === 200) {
        const data = response.body;

        if (Array.isArray(data) && data.length > 0) {
          const primeiro = data[0];

          if (primeiro.success && primeiro.data) {
            debug.sucesso('REQUISICAO_SUCESSO', {
              tentativa,
              token: tokenMascara
            });
            return { 
              sucesso: true, 
              dados: primeiro.data, 
              token_usado: tokenMascara 
            };
          }
        }

        debug.log(`TENTATIVA_${tentativa}_FALHOU`, {
          motivo: 'Resposta sem estrutura esperada'
        });
        continue;
      }

      if (response.statusCode === 404) {
        debug.erro('REQUISICAO_404', 'Número não encontrado');
        return { 
          sucesso: false, 
          erro: 'not_found', 
          mensagem: 'Número não encontrado' 
        };
      }

      debug.log(`TENTATIVA_${tentativa}_ERRO_HTTP`, {
        status: response.statusCode
      });
      continue;

    } catch (erro) {
      ultimoErro = erro.message;
      debug.erro(`TENTATIVA_${tentativa}_EXCEPTION`, {
        erro: erro.message
      });
      continue;
    }
  }

  debug.erro('TODAS_TENTATIVAS_FALHARAM', {
    total_tentativas: tentativa,
    ultimo_erro: ultimoErro
  });

  return { 
    sucesso: false, 
    erro: 'all_tokens_failed', 
    mensagem: ultimoErro || 'Todos tokens falharam' 
  };
}

// ==========================================
// RESOLUÇÃO LID/JID
// ==========================================
async function resolverLidParaJid(lid, debug) {
  debug.log('RESOLVER_LID_PARA_JID', { lid });
  return await requisicaoComFallback('/user/lid/from-lid', { lid }, debug);
}

async function resolverJidParaLid(jid, debug) {
  const numeroLimpo = jid.split('@')[0].split(':')[0];

  debug.log('RESOLVER_JID_PARA_LID', { 
    jid_original: jid, 
    phone_enviado: numeroLimpo 
  });

  const resultado = await requisicaoComFallback('/user/lid/get', { 
    phone: numeroLimpo 
  }, debug);

  if (resultado.sucesso && resultado.dados) {
    if (resultado.dados.has_lid && resultado.dados.lid) {
      debug.sucesso('LID_ENCONTRADO_PARA_JID', {
        lid: resultado.dados.lid
      });
      return resultado;
    } else {
      debug.log('JID_SEM_LID', 'Número válido mas sem LID');
      return {
        sucesso: false,
        erro: 'no_lid',
        mensagem: 'Número válido mas sem LID'
      };
    }
  }

  return resultado;
}

// ==========================================
// PROCESSAMENTO PRINCIPAL
// ==========================================
const items = $input.all();
const resultados = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const debug = new DebugLogger();

  debug.log('PROCESSANDO_ITEM', { 
    index: i + 1,
    total: items.length 
  });

  const webhook = extrairDadosWebhook(item, debug);

  if (!webhook.identificador) {
    debug.erro('VALIDACAO_WEBHOOK', 'Identificador não encontrado');

    resultados.push({
      json: {
        ...item.json,
        _whatsapp: {
          erro: 'identificador_ausente',
          mensagem: 'Não foi possível extrair JID/LID do webhook'
        },
        _debug: debug.getLogs(),
        _debug_resumo: debug.getResumo()
      }
    });
    continue;
  }

  // CASO ESPECIAL: JÁ TEM LID E JID
  if (webhook.lid && webhook.jid) {
    debug.log('JID_E_LID_DISPONIVEIS', {
      lid: webhook.lid,
      jid: webhook.jid
    });

    const telefone = webhook.jid.split('@')[0].split(':')[0];

    const dadosFinais = {
      identificador_recebido: webhook.identificador,
      tipo_recebido: 'jid_com_lid',
      nome_contato: webhook.nome,
      mensagem_recebida: webhook.mensagem,
      tipo_mensagem: webhook.tipo_mensagem,
      midia: webhook.midia,
      jid: webhook.jid,
      lid: webhook.lid,
      telefone: telefone,
      identificador_ativo: webhook.jid,
      resolvido: true,
      has_lid: true,
      erro: null
    };

    debug.sucesso('LID_E_JID_JA_RESOLVIDOS', dadosFinais);

    resultados.push({
      json: {
        ...webhook.webhook_completo,
        _whatsapp: dadosFinais,
        _debug: debug.getLogs(),
        _debug_resumo: debug.getResumo()
      }
    });
    continue;
  }

  // FLUXO NORMAL
  const identificacao = identificarTipo(webhook.identificador, debug);

  let dadosFinais = {
    identificador_recebido: webhook.identificador,
    tipo_recebido: identificacao.tipo,
    nome_contato: webhook.nome,
    mensagem_recebida: webhook.mensagem,
    tipo_mensagem: webhook.tipo_mensagem,
    midia: webhook.midia,
    jid: webhook.jid,
    lid: webhook.lid,
    telefone: null,
    identificador_ativo: webhook.identificador,
    resolvido: false,
    has_lid: !!webhook.lid,
    erro: null
  };

  if (identificacao.tipo === 'jid') {
    dadosFinais.telefone = identificacao.telefone;
    dadosFinais.identificador_ativo = identificacao.valor;
    dadosFinais.resolvido = true;

    debug.sucesso('JID_PROCESSADO', {
      jid: dadosFinais.jid,
      telefone: dadosFinais.telefone
    });

    // Busca LID opcional se ainda não tem
    if (!dadosFinais.lid) {
      const resultadoLid = await resolverJidParaLid(identificacao.valor, debug);
      if (resultadoLid.sucesso) {
        dadosFinais.lid = resultadoLid.dados.lid;
        dadosFinais.has_lid = true;
      }
    }
  }
  else if (identificacao.tipo === 'lid') {
    const resultado = await resolverLidParaJid(identificacao.valor, debug);

  if (resultado.sucesso) {
  dadosFinais.jid = resultado.dados.phone;

  // Extrai telefone SEM normalizar
  const partes = resultado.dados.phone.split('@')[0];
  dadosFinais.telefone = partes.split(':')[0];

  dadosFinais.identificador_ativo = resultado.dados.phone;
  dadosFinais.resolvido = true;

  debug.sucesso('LID_RESOLVIDO', {
    lid_original: dadosFinais.lid,
    jid_encontrado: dadosFinais.jid,
    telefone: dadosFinais.telefone
  });
} else {
  dadosFinais.resolvido = false;
  dadosFinais.erro = resultado.erro;

  debug.erro('FALHA_RESOLVER_LID', {
    erro: resultado.erro
  });
}
  }

  resultados.push({
    json: {
      ...webhook.webhook_completo,
      _whatsapp: dadosFinais,
      _debug: debug.getLogs(),
      _debug_resumo: debug.getResumo()
    }
  });
}

return resultados;

